/** user-defined types **/

export type Account = { id: string; owner: string; bank: string; type: AccountType; name: string; last4: string | null; currency: string; color: string; archived_at: string | null; liquidity_type: string; emergency_fund_eligible: boolean; goal_earmark: string | null; apy_pct: number | null; created_at: string; simplefin_account_id: string | null; last_synced_at: string | null; nickname: string | null; connection_id: string | null; institution_id: string | null; external_account_id: string | null; official_name: string | null; mask: string | null; subtype: string | null; account_group: string; available_balance_cents: number | null; balance_date: string | null; extra_json: string | null; raw_json: string | null; import_pending: boolean; 
/**
 * Debt fields, meaningful only for Credit/Loan-type accounts (shown
 * conditionally in the UI, mirroring `apy_pct` for Savings). Together
 * these let a Credit/Loan account fully replace the standalone
 * liability-tracking model: a debt is just an account with a negative
 * balance and these optional details, not a separate entity.
 */
apr_pct: number | null; min_payment_cents: number | null; payoff_date: string | null; limit_cents: number | null; original_balance_cents: number | null; started_at: string | null }
export type AccountBalancePoint = { date: string; balanceCents: number }
/**
 * A reconstructed balance curve for one account, derived from its opening
 * anchor plus cleared transaction activity.
 */
export type AccountBalanceTimeline = { accountId: string; accountName: string; 
/**
 * End-of-day balance for each day the account saw activity, ascending.
 * Empty when the account is not reconstructable.
 */
points: AccountBalancePoint[]; 
/**
 * Highest and lowest end-of-day balance within the requested window.
 * Ties resolve to the earliest date. `None` when there are no points.
 */
peak: AccountBalancePoint | null; trough: AccountBalancePoint | null; 
/**
 * Balance at the end of the series — the reconstruction's answer for today.
 */
currentCents: number; anchor: BalanceAnchorQuality; 
/**
 * Earliest cleared transaction *included in this curve*. History cannot
 * reach back further, so a peak before it would be invisible.
 */
earliestTxnDate: string | null; 
/**
 * False when the balance cannot be honestly derived from the ledger. See
 * [`AccountBalanceTimeline::skip_reason`] for which case applies.
 */
reconstructable: boolean; 
/**
 * Why reconstruction was refused, phrased for a human (or a model) to
 * relay. `None` when `reconstructable` is true.
 */
skipReason: string | null }
/**
 * One (account, member) ownership pair with the member's explicit share, if
 * any. The full list lets the UI derive sole/joint badges and per-member
 * net-worth attribution in one query. `share_bps` None = equal split.
 */
export type AccountOwner = { accountId: string; memberId: string; shareBps: number | null }
export type AccountPatch = { name: string | null; bank: string | null; account_type: AccountType | null; color: string | null; last4: string | null; currency: string | null; liquidity_type: string | null; emergency_fund_eligible: boolean | null; goal_earmark: string | null; apy_pct: number | null; nickname: string | null; official_name: string | null; subtype: string | null; account_group: string | null; import_pending: boolean | null; apr_pct: number | null; min_payment_cents: number | null; payoff_date: string | null; limit_cents: number | null; original_balance_cents: number | null; started_at: string | null }
export type AccountSparkline = { accountId: string; points: AccountBalancePoint[] }
export type AccountSummary = { id: string; owner: string; bank: string; type: AccountType; name: string; balance_cents: number; 
/**
 * False when `balance_cents` is just the untouched account-creation seed
 * value and the account has transaction activity that could have moved
 * the real balance since then. The UI must not present `balance_cents`
 * as a trustworthy current balance when this is false.
 */
balance_known?: boolean; 
/**
 * Source of the snapshot `balance_cents` came from: `simplefin` (bank-
 * reported), `manual` (legacy user-stamped), `derived` (computed from
 * opening + activity), or `seed` (untouched opening). Lets the UI show the
 * balance's basis — "synced", "estimated from your transactions", etc.
 */
balance_source?: string | null; currency: string; color: string; source: string; liquidity_type?: string; emergency_fund_eligible?: boolean; goal_earmark: string | null; apy_pct: number | null; simplefin_account_id: string | null; last_synced_at: string | null; nickname: string | null; connection_id: string | null; institution_id: string | null; external_account_id: string | null; official_name: string | null; mask: string | null; subtype: string | null; account_group: string; available_balance_cents: number | null; balance_date: string | null; extra_json: string | null; raw_json: string | null; import_pending: boolean; apr_pct: number | null; min_payment_cents: number | null; payoff_date: string | null; limit_cents: number | null; original_balance_cents: number | null; started_at: string | null }
export type AccountSyncResult = { accountId: string; added: number; updated: number; skipped: number; queuedForReview: number; error: string | null }
export type AccountType = "Checking" | "Savings" | "Credit" | "Investment" | "Cash" | "Loan" | "Other"
/**
 * A single prioritized action item in the Financial Inbox.
 */
export type ActionItem = { 
/**
 * Stable ID for this item — used as React key and for deduplication.
 */
id: string; 
/**
 * "review" | "bills" | "budget" | "goals" | "savings"
 */
category: string; 
/**
 * "high" | "medium" | "low"
 */
priority: string; title: string; detail: string; actionLabel: string; 
/**
 * Frontend route the CTA navigates to (e.g., "/transactions").
 */
actionRoute: string; 
/**
 * Optional count for badge display (e.g., number of uncategorized txns).
 */
badgeCount: number | null; 
/**
 * Optional monetary amount in cents (e.g., bill amount).
 */
amountCents: number | null }
export type AgentAccountRow = { name: string; subtitle: string | null; typeLabel: string; 
/**
 * None → account has no known balance; renderer shows `badge` instead.
 */
amountCents: number | null; badge: string | null }
export type AgentAccountsOverviewBlock = { title: string | null; subtitle: string | null; rows: AgentAccountRow[] }
export type AgentActionBundle = { id: string; sessionId: string | null; title: string; summary: string; rationale: string; confidence: number; status: string; providerId: string | null; modelId: string | null; createdAt: string; updatedAt: string; items: AgentActionItem[] }
export type AgentActionItem = { id: string; bundleId: string; actionKind: string; payloadJson: string; previewJson: string | null; rationale: string; confidence: number; status: string; validationErrors: string | null; sortOrder: number; createdAt: string; updatedAt: string }
export type AgentActionPlanBlock = { title: string | null; items: string[] }
export type AgentActivity = { text: string; sub: string; minutesAgo: number }
export type AgentAffordabilityVerdictBlock = { canAfford: boolean; headline: string; sub: string; caveat: string | null; fundingSource: AgentFundingSource | null }
